559	func (m *WorkerManager) runWorker(ctx context.Context, id, dir string, spec ExecuteLoopWorkerSpec, projectRoot string, handle *workerHandle, log io.Writer, eventSink io.WriteCloser, progressCh chan agent.ProgressEvent) {
560		if eventSink != nil {
561			defer eventSink.Close() //nolint:errcheck
562		}
563		store := bead.NewStore(filepath.Join(projectRoot, ".ddx"))
564	
565		var worker *agent.ExecuteBeadWorker
566		if m.BeadWorkerFactory != nil {
567			worker = m.BeadWorkerFactory(store)
568		} else {
569			// Build an executor that calls agent.ExecuteBead in-process, then
570			// submits the result to the project's land coordinator. The
571			// coordinator (a single goroutine per projectRoot) serializes all
572			// target-ref writes for this project — this is the server-side
573			// implementation of the human-PR landing model. See ddx-8746d8a6
574			// for the rationale. Prior to this rewrite, runWorker never called
575			// LandBeadResult at all, so commits produced by server-managed
576			// workers were silently lost (ddx-e14efc58).
577			coordinator := m.LandCoordinators.Get(projectRoot)
578	
579			// singleTierAttempt runs one execution at a specific harness/model.
580			singleTierAttempt := func(ctx context.Context, beadID string, tier escalation.ModelTier, resolvedHarness, resolvedProvider, resolvedModel string) (agent.ExecuteBeadReport, error) {
581				gitOps := &agent.RealGitOps{}
582				attemptProvider := spec.Provider
583				if resolvedProvider != "" {
584					attemptProvider = resolvedProvider
585				}
586				attemptRcfg, _ := config.LoadAndResolve(projectRoot, config.CLIOverrides{
587					Harness:  resolvedHarness,
588					Model:    resolvedModel,
589					Provider: attemptProvider,
590					ModelRef: spec.ModelRef,
591					Effort:   spec.Effort,
592				})
593				res, err := agent.ExecuteBeadWithConfig(ctx, projectRoot, beadID, attemptRcfg, agent.ExecuteBeadRuntime{
594					BeadEvents: bead.NewStore(filepath.Join(projectRoot, ".ddx")),
595				}, gitOps)
596				if err != nil && res == nil {
597					return agent.ExecuteBeadReport{}, err
598				}
599				if res != nil && res.ResultRev != "" && res.ResultRev != res.BaseRev && res.ExitCode == 0 {
600					if landErr := evaluateGatesAndSubmit(projectRoot, res, gitOps, coordinator, log); landErr != nil && err == nil {
601						err = landErr
602					}
603				} else if res != nil && res.ResultRev == res.BaseRev {
604					res.Outcome = "no-changes"
605					res.Status = agent.ClassifyExecuteBeadStatus(res.Outcome, res.ExitCode, res.Reason)
606				} else if res != nil && res.ExitCode != 0 {
607					res.Outcome = "preserved"
608					res.Status = agent.ClassifyExecuteBeadStatus(res.Outcome, res.ExitCode, res.Reason)
609				}
610				// Safety net: commit any leftover evidence files that Land()
611				// did not pick up (e.g. HEAD was detached, or no land ran).
612				if res != nil && res.AttemptID != "" {
613					_ = agent.VerifyCleanWorktree(projectRoot, res.AttemptID)
614				}
615				if err != nil {
616					return agent.ExecuteBeadReport{}, err
617				}
618				tierStr := ""
619				if tier != "" {
620					tierStr = string(tier)
621				}
622				return agent.ExecuteBeadReport{
623					BeadID:             res.BeadID,
